// ─── Assets « coups de pinceau » du thème Élégant ───────────────────────────────
//
// Textures de peinture (impasto) découpées de la maquette papier MomentD.Art puis
// détourées par matte alpha, débruitées (NL-means), suréchantillonnées (Lanczos ×2)
// et accentuées pour le relief, enfin quantifiées (RGBA 256c) pour le poids.
// Le fond de page beige correspond au fond des découpes → aucun liseré visible.
//
// Généré depuis src/docs/paint_top.png et src/docs/paint_botleft.png (voir src/docs/README.md).

/** Rectangle de placement d'une texture, en points PDF (origine coin haut-gauche). */
export type PaintRect = { x: number; y: number; w: number };

/** Sweep de peinture en haut (entre le logo et le bloc DEVIS). */
export const ELEGANT_PAINT_TOP_RECT: PaintRect = { x: 204.26, y: 0.0, w: 220.06 };

/** Sweep de peinture dans le coin bas-gauche. */
export const ELEGANT_PAINT_BOTLEFT_RECT: PaintRect = { x: 0.0, y: 709.2, w: 125.26 };

